import React from 'react';
import Card from 'react-bootstrap/Card';

function CustomCard({ content, width, height }) {
  return (
    <Card style={{ width: width, height: height }}>
      <Card.Body>
        {content}
      </Card.Body>
    </Card>
  );
}

export default CustomCard;
